def is_admin() -> bool:
    """Vérifie si l'application tourne avec les droits administrateur."""
    try:
        return ctypes.windll.shell32.IsUserAnAdmin()
    except Exception:
        return False


def elevate_admin():
    """Relance l'application avec les droits administrateur via UAC."""
    ctypes.windll.shell32.ShellExecuteW(
        None, "runas", sys.executable, " ".join(sys.argv), None, 1
    )
    sys.exit(0)


import base64
import tempfile

SCRIPTS_EMBEDDED = {
    "01_nettoyage_temp.ps1": "",
    "02_optimisation_demarrage.ps1": "",
    "03_nettoyage_registre.ps1": "",
    "04_scan_malwares.ps1": "",
    "05_reparation_systeme.ps1": "",
    "06_optimisation_ram.ps1": "",
    "07_detection_drivers.ps1": "",
    "08_sante_disque.ps1": "",
    "09_reparation_reseau.ps1": "",
    "10_rapport_final.ps1": "",
}

def get_scripts_dir() -> Path:
    """Extrait les scripts PS1 embarqués dans C:\\NELVIS\\scripts\ (hors TEMP) et retourne son chemin."""
    # IMPORTANT : Ne pas utiliser tempfile.mkdtemp() car le script 01 nettoie le dossier TEMP
    # et supprimerait les scripts 02-10 pendant l'exécution.
    scripts_dir = Path("C:/NELVIS/scripts")
    scripts_dir.mkdir(parents=True, exist_ok=True)
    for script_name, b64_content in SCRIPTS_EMBEDDED.items():
        script_content = base64.b64decode(b64_content).decode('utf-8')
        script_path = scripts_dir / script_name
        script_path.write_text(script_content, encoding='utf-8')
    return scripts_dir


def run_powershell(script_path: Path) -> dict:
    """Exécute un script PowerShell et retourne son output JSON."""
    try:
        result = subprocess.run(
            [
                "powershell.exe",
                "-NoProfile",
                "-NonInteractive",
                "-ExecutionPolicy", "Bypass",
                "-File", str(script_path),
            ],
            capture_output=True,
            text=True,
            timeout=900,  # 15 minutes max par script
        )
        stdout = result.stdout.strip()
        if stdout:
            # Extraire uniquement le JSON (ignorer les lignes non-JSON)
            lines = stdout.split("\n")
            json_start = -1
            for i, line in enumerate(lines):
                if line.strip().startswith("{"):
                    json_start = i
                    break
            if json_start >= 0:
                json_str = "\n".join(lines[json_start:])
                return json.loads(json_str)
        return {"statut_global": "succes", "output": stdout}
    except subprocess.TimeoutExpired:
        return {"statut_global": "timeout", "message": "Script interrompu après 15 minutes"}
    except json.JSONDecodeError:
        return {"statut_global": "succes", "output": result.stdout[:500]}
    except Exception as e:
        return {"statut_global": "erreur", "message": str(e)}


def generate_pdf_report(results: list[dict]) -> Path:
    """Génère un rapport PDF sur le Bureau de l'utilisateur."""
    bureau = Path.home() / "Desktop"
    bureau.mkdir(exist_ok=True)
    rapport_path = bureau / "rapport_NELVIS.txt"

    lines = [
        "=" * 60,
        "  NELVIS PC Doctor — Rapport de réparation",
        f"  Date : {time.strftime('%d/%m/%Y à %H:%M:%S')}",
        "=" * 60,
        "",
    ]

    for i, (etape_nom, _) in enumerate(ETAPES):
        result = results[i] if i < len(results) else {}
        statut = result.get("statut_global", "non_execute")
        emoji = "✓" if statut in ("succes", "termine") else "✗"
        lines.append(f"  {emoji}  Étape {i+1:02d} : {etape_nom}")
        lines.append(f"       Statut : {statut}")

        # Détails spécifiques par script
        if i == 0 and "total_mo_liberes" in result:
            lines.append(f"       Mo libérés : {result['total_mo_liberes']} Mo")
        elif i == 1 and "programmes_desactives_count" in result:
            lines.append(f"       Programmes désactivés : {result['programmes_desactives_count']}")
        elif i == 2 and "entrees_supprimees_count" in result:
            lines.append(f"       Clés supprimées : {result['entrees_supprimees_count']}")
        elif i == 3 and "menaces_count" in result:
            lines.append(f"       Menaces détectées : {result['menaces_count']}")
        elif i == 5 and "mo_recuperes" in result:
            lines.append(f"       Mo RAM récupérés : {result['mo_recuperes']} Mo")
        elif i == 7 and "score_sante_global_pct" in result:
            lines.append(f"       Santé disque : {result['score_sante_global_pct']}%")
        lines.append("")

    lines += [
        "=" * 60,
        "  Rapport JSON complet : C:\\NELVIS\\rapport_final.json",
        "  Support : contact@nelvis.fr | +33 7 45 99 47 76",
        "=" * 60,
    ]

    rapport_path.write_text("\n".join(lines), encoding="utf-8")
    return rapport_path


