class NelvisApp(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("NELVIS PC Doctor")
        self.geometry("520x580")
        self.resizable(False, False)
        self.configure(bg=C_BG)
        self.protocol("WM_DELETE_WINDOW", self._on_close)

        # Centrer la fenêtre
        self.update_idletasks()
        x = (self.winfo_screenwidth()  - 520) // 2
        y = (self.winfo_screenheight() - 580) // 2
        self.geometry(f"520x580+{x}+{y}")

        # Polices
        self.font_title  = tkfont.Font(family="Segoe UI", size=20, weight="bold")
        self.font_sub    = tkfont.Font(family="Segoe UI", size=10)
        self.font_label  = tkfont.Font(family="Segoe UI", size=11)
        self.font_code   = tkfont.Font(family="Consolas",  size=13, weight="bold")
        self.font_step   = tkfont.Font(family="Segoe UI", size=10)
        self.font_btn    = tkfont.Font(family="Segoe UI", size=12, weight="bold")

        self._build_ui()

    def _build_ui(self):
        """Construit l'interface d'accueil."""
        # En-tête
        header = tk.Frame(self, bg=C_BG)
        header.pack(fill="x", pady=(32, 0))

        tk.Label(header, text="🧠", font=("Segoe UI Emoji", 36),
                 bg=C_BG, fg=C_ORANGE).pack()
        tk.Label(header, text="NELVIS PC Doctor",
                 font=self.font_title, bg=C_BG, fg=C_TEXT).pack(pady=(4, 0))
        tk.Label(header, text="Assistant intelligent de réparation PC",
                 font=self.font_sub, bg=C_BG, fg=C_MUTED).pack(pady=(2, 0))

        # Séparateur
        tk.Frame(self, bg=C_BORDER, height=1).pack(fill="x", padx=40, pady=20)

        # Carte licence
        card = tk.Frame(self, bg=C_CARD, bd=0, relief="flat")
        card.pack(fill="x", padx=40)

        inner = tk.Frame(card, bg=C_CARD)
        inner.pack(fill="x", padx=24, pady=24)

        tk.Label(inner, text="Entrez votre code de licence",
                 font=self.font_label, bg=C_CARD, fg=C_TEXT).pack(anchor="w")
        tk.Label(inner, text="Format : NELVIS-XXXX-XXXX",
                 font=self.font_sub, bg=C_CARD, fg=C_MUTED).pack(anchor="w", pady=(2, 12))

        # Champ de saisie
        entry_frame = tk.Frame(inner, bg=C_ORANGE, bd=2)
        entry_frame.pack(fill="x")
        self.entry_code = tk.Entry(
            entry_frame,
            font=self.font_code,
            bg=C_BG,
            fg=C_TEXT,
            insertbackground=C_ORANGE,
            relief="flat",
            bd=8,
        )
        self.entry_code.pack(fill="x")
        self.entry_code.bind("<Return>", lambda e: self._valider())

        # Message d'erreur
        self.lbl_error = tk.Label(inner, text="", font=self.font_sub,
                                   bg=C_CARD, fg=C_ERROR)
        self.lbl_error.pack(anchor="w", pady=(8, 0))

        # Bouton valider
        self.btn_valider = tk.Button(
            inner,
            text="Valider et lancer la réparation",
            font=self.font_btn,
            bg=C_ORANGE,
            fg="white",
            activebackground="#ea6a0a",
            activeforeground="white",
            relief="flat",
            bd=0,
            padx=20,
            pady=12,
            cursor="hand2",
            command=self._valider,
        )
        self.btn_valider.pack(fill="x", pady=(16, 0))

        # Séparateur
        tk.Frame(self, bg=C_BORDER, height=1).pack(fill="x", padx=40, pady=20)

        # Zone de progression (cachée au départ)
        self.frame_progress = tk.Frame(self, bg=C_BG)
        self.frame_progress.pack(fill="x", padx=40)

        self.lbl_step = tk.Label(self.frame_progress, text="",
                                  font=self.font_step, bg=C_BG, fg=C_MUTED)
