    def _valider(self):
        """Valide le code licence auprès de Supabase."""
        code = self.entry_code.get().strip().upper()
        if not code:
            self.lbl_error.config(text="Veuillez entrer votre code de licence.")
            return

        self.lbl_error.config(text="")
        self.btn_valider.config(state="disabled", text="Vérification en cours…")
        self.update()

        threading.Thread(target=self._check_license, args=(code,), daemon=True).start()

    def _check_license(self, code: str):
        """Appel API Supabase en arrière-plan."""
        try:
            response = requests.post(
                CHECK_LICENSE_URL,
                json={"code": code},
                headers={
                    "Content-Type": "application/json",
                    "apikey": SUPABASE_ANON_KEY,
                },
                timeout=15,
            )
            data = response.json()
        except requests.exceptions.ConnectionError:
            self.after(0, self._on_network_error)
            return
        except Exception as e:
            self.after(0, lambda: self._on_error(str(e)))
            return

        if data.get("valid") is True:
            self.after(0, self._start_repair)
        else:
            reason = data.get("reason", "")
            msg = {
                "code_introuvable":  "Code invalide. Vérifiez votre email de confirmation.",
                "code_deja_utilise": "Ce code a déjà été utilisé sur un autre PC.",
                "format_invalide":   "Format incorrect. Exemple : NELVIS-AB12-CD34",
            }.get(reason, "Code invalide ou déjà utilisé.")
            self.after(0, lambda: self._on_invalid_code(msg))

    def _on_invalid_code(self, message: str):
        self.lbl_error.config(text=f"✗  {message}", fg=C_ERROR)
        self.btn_valider.config(state="normal", text="Valider et lancer la réparation")

    def _on_network_error(self):
        self.lbl_error.config(
            text="✗  Impossible de contacter le serveur. Vérifiez votre connexion internet.",
            fg=C_ERROR
        )
        self.btn_valider.config(state="normal", text="Valider et lancer la réparation")

    def _on_error(self, message: str):
        self.lbl_error.config(text=f"✗  Erreur : {message}", fg=C_ERROR)
        self.btn_valider.config(state="normal", text="Valider et lancer la réparation")

    def _start_repair(self):
        """Lance la séquence de réparation dans un thread séparé."""
        self.btn_valider.config(state="disabled", text="Réparation en cours…")
        self.entry_code.config(state="disabled")
        self.lbl_error.config(text="✓  Code validé — réparation en cours…", fg=C_SUCCESS)
        self.progress_bar["value"] = 0
        threading.Thread(target=self._run_repair, daemon=True).start()

    def _run_repair(self):
        """Exécute les 10 scripts PowerShell dans l'ordre."""
        scripts_dir = get_scripts_dir()
        results = []
        total = len(ETAPES)

        for i, (nom_etape, nom_script) in enumerate(ETAPES):
            # Mise à jour de l'interface
            pct = int(i / total * 100)
            self.after(0, lambda n=nom_etape, p=pct: self._update_progress(n, p))

            script_path = scripts_dir / nom_script
            if script_path.exists():
                result = run_powershell(script_path)
            else:
                result = {"statut_global": "fichier_absent", "script": nom_script}
            results.append(result)

        # Progression finale
        self.after(0, lambda: self._update_progress("Génération du rapport…", 95))

        # Génération du rapport sur le Bureau
        rapport_path = generate_pdf_report(results)

        # Fin
        self.after(0, lambda: self._on_repair_complete(rapport_path))

    def _update_progress(self, step_name: str, pct: int):
        self.lbl_step.config(text=f"⚙  {step_name}")
        self.progress_bar["value"] = pct
        self.lbl_pct.config(text=f"{pct}%")

    def _on_repair_complete(self, rapport_path: Path):
        """Affiche l'écran de succès et ouvre le rapport."""
        self.progress_bar["value"] = 100
        self.lbl_pct.config(text="100%")
        self.lbl_step.config(text="✓  Réparation terminée !", fg=C_SUCCESS)
        self.lbl_error.config(
            text="Votre rapport est sur le Bureau.",
            fg=C_SUCCESS
        )
        self.btn_valider.config(
            state="normal",
            text="Ouvrir le rapport",
            bg=C_SUCCESS,
            command=lambda: os.startfile(str(rapport_path)),
        )

        messagebox.showinfo(
            "NELVIS PC Doctor — Réparation terminée",
            f"✓  Réparation terminée avec succès !\n\n"
            f"Votre rapport a été enregistré sur le Bureau :\n"
            f"{rapport_path.name}\n\n"
            f"Un redémarrage de votre PC est recommandé\n"
            f"pour finaliser toutes les réparations.",
        )

        # Ouvrir automatiquement le rapport
        try:
            os.startfile(str(rapport_path))
        except Exception:
            pass

    def _on_close(self):
        if messagebox.askokcancel("Quitter", "Voulez-vous vraiment quitter NELVIS PC Doctor ?"):
            self.destroy()


